            for d in (0..rank - 1).rev() {
                chunk_strides[d] = chunk_strides[d + 1] * actual_chunk_shape[d + 1];
            }

            let mut subset_end_exclusive = vec![0u64; rank];
            for d in 0..rank {
                subset_end_exclusive[d] = subset_start[d] + subset_shape[d];
            }

            let total: u64 = subset_shape.iter().product();
            let mut out = Vec::with_capacity(total as usize);
            let mut idx = subset_start.clone();
            for _ in 0..total { // iterate through all elements in the subset
                // Calculate flat index in the full chunk for the current element
                let mut flat: u64 = 0;
                for d in 0..rank {
                    flat += idx[d] * chunk_strides[d];
                }
                out.push(full[flat as usize].clone());
                for d in (0..rank).rev() {
                    idx[d] += 1;
                    if idx[d] < subset_end_exclusive[d] {
