use std::sync::Arc;
use zarrs::array::{Array, ElementOwned};
use zarrs::array_subset::ArraySubset;
use zarrs::storage::ReadableStorageTraits;

pub struct GridIterator {
    current: Option<Vec<u64>>,
    bounds_min: Vec<u64>,
    bounds_max: Vec<u64>,
}

impl GridIterator {
    pub fn new(
        bounds_min: &[u64],
        bounds_max: &[u64],
        _shape: &[u64],
        chunk_shape: &[u64],
    ) -> Self {
        let rank = bounds_min.len();
        let mut min = vec![0u64; rank];
        let mut max = vec![0u64; rank];
        for i in 0..rank {
            min[i] = bounds_min[i] / chunk_shape[i];
            max[i] = bounds_max[i] / chunk_shape[i];
        }
        Self {
            current: Some(min.clone()),
            bounds_min: min,
            bounds_max: max,
        }
    }
}

impl Iterator for GridIterator {
    type Item = Vec<u64>;

    fn next(&mut self) -> Option<Self::Item> {
        let current = self.current.take()?;
        let mut next_grid = current.clone();

        let rank = next_grid.len();
        let mut exhausted = true;
        for i in (0..rank).rev() {
            if next_grid[i] < self.bounds_max[i] {
                next_grid[i] += 1;
                exhausted = false;
                break;
            } else {
                next_grid[i] = self.bounds_min[i];
            }
        }

        if !exhausted {
            self.current = Some(next_grid);
        }

        Some(current)
    }
}

#[derive(Default, Clone)]
pub struct SubsetInfo {
    pub global_starts: Vec<u64>,
    pub shape: Vec<u64>,
    pub strides: Vec<u64>,
}

impl SubsetInfo {
    pub fn global_coord(&self, dim: usize, local_pos: u64) -> u64 {
        self.global_starts[dim] + (local_pos / self.strides[dim]) % self.shape[dim]
    }
}

pub struct ChunkReader {
    pub array: Arc<Array<dyn ReadableStorageTraits>>,
    pub is_remote: bool,
    pub shape: Vec<u64>,
    pub chunk_shape: Vec<u64>,
}

impl ChunkReader {
    pub fn new(
        array: Arc<Array<dyn ReadableStorageTraits>>,
        is_remote: bool,
        shape: Vec<u64>,
        chunk_shape: Vec<u64>,
    ) -> Self {
        Self {
            array,
            is_remote,
            shape,
            chunk_shape,
        }
    }

    pub fn read_chunk_subset<T: ElementOwned + Clone>(
        &self,
        grid_coord: &[u64],
        bounds_min: &[u64],
        bounds_max: &[u64],
    ) -> Result<(Vec<T>, SubsetInfo), String> {
        let rank = self.shape.len();
        let mut subset_start = vec![0u64; rank];
        let mut subset_shape = vec![0u64; rank];
        let mut global_starts = vec![0u64; rank];
        let mut strides = vec![1u64; rank];

        for d in 0..rank {
            let chunk_start = grid_coord[d] * self.chunk_shape[d];
            let chunk_end_inc = chunk_start + self.chunk_shape[d] - 1;
            let lo = bounds_min[d].max(chunk_start);
            let hi = bounds_max[d].min(chunk_end_inc);
            subset_start[d] = lo - chunk_start;
            subset_shape[d] = hi - lo + 1;
            global_starts[d] = lo;
        }
        for d in (0..rank - 1).rev() {
            strides[d] = strides[d + 1] * subset_shape[d + 1];
        }

        let elements: Vec<T> = if self.is_remote {
            let full = self
                .array
                .retrieve_chunk_elements::<T>(grid_coord)
                .map_err(|e| format!("zarrs read error: {}", e))?;
            let actual_chunk_shape: Vec<u64> = (0..rank)
                .map(|d| {
                    let chunk_start = grid_coord[d] * self.chunk_shape[d];
                    let chunk_end_inc = chunk_start + self.chunk_shape[d] - 1;
                    let actual_end = self.shape[d].min(chunk_end_inc + 1);
                    actual_end - chunk_start
                })
                .collect();
            let mut chunk_strides = vec![1u64; rank];
            for d in (0..rank - 1).rev() {
                chunk_strides[d] = chunk_strides[d + 1] * actual_chunk_shape[d + 1];
            }
            let total: u64 = subset_shape.iter().product();

            // Handle 0-dimensional arrays (scalars) separately.
            if rank == 0 {
                let mut out = Vec::with_capacity(1);
                out.push(full[0].clone());
                out
            } else {
                let mut out = Vec::with_capacity(total as usize);
                let mut current_idx = subset_start.clone();
                let mut remaining_elements_to_copy = total;

                // Initialize base_flat_idx for dimensions 0 to rank-2
                let mut base_flat_idx: u64 = 0;
                for d in 0..rank - 1 {
                    base_flat_idx += current_idx[d] * chunk_strides[d];
                }

                while remaining_elements_to_copy > 0 {
                    // The start index in the 'full' chunk for the current contiguous slice
                    let start_of_slice_in_full_dim = current_idx[rank - 1] * chunk_strides[rank - 1];
                    let start_of_slice_in_full = (base_flat_idx + start_of_slice_in_full_dim) as usize;

                    // The number of elements to copy in this contiguous "row"
                    let end_of_last_dim_in_subset = subset_start[rank - 1] + subset_shape[rank - 1];
                    let num_elements_in_row = end_of_last_dim_in_subset - current_idx[rank - 1];

                    // Append this contiguous slice directly
                    out.extend_from_slice(&full[start_of_slice_in_full .. start_of_slice_in_full + num_elements_in_row as usize]);

                    remaining_elements_to_copy -= num_elements_in_row;

                    // Increment `current_idx` for the next "row" or multi-dimensional block
                    // Reset innermost dim for next "row"
                    current_idx[rank - 1] = subset_start[rank - 1];

                    // Increment from rank-2 down to 0, handling carry-overs
                    for d in (0..rank - 1).rev() {
                        current_idx[d] += 1;
                        base_flat_idx += chunk_strides[d]; // Adjust base_flat_idx for the increment

                        // If we are still within the bounds of this dimension's subset shape
                        if current_idx[d] < subset_start[d] + subset_shape[d] {
                            break; // No carry-over needed for this dimension, move to next "row"
                        }
                        // Carry over: reset this dimension
                        base_flat_idx -= subset_shape[d] * chunk_strides[d]; // Subtract the contribution of the entire span of this dimension's subset shape
                        current_idx[d] = subset_start[d]; // Reset current_idx[d]
                    }
                }
                out
            }
        } else {
            let chunk_subset =
                ArraySubset::new_with_start_shape(subset_start.clone(), subset_shape.clone())
                    .map_err(|e| format!("Invalid chunk subset: {}", e))?;
            self.array
                .retrieve_chunk_subset_elements::<T>(grid_coord, &chunk_subset)
                .map_err(|e| format!("zarrs read error: {}", e))?
        };

        Ok((
            elements,
            SubsetInfo {
                global_starts,
                shape: subset_shape,
                strides,
            },
        ))
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use zarrs::array::{ArrayBuilder, DataType, FillValue};
    use zarrs::array::chunk_grid::{ChunkGrid, RegularChunkGrid};
    use zarrs::storage::store::MemoryStore;

    #[test]
    fn test_read_chunk_subset() {
        let store = Arc::new(MemoryStore::new());
        let shape = vec![10, 10];
        let chunk_shape = vec![5, 5];

        let array_write = ArrayBuilder::new(
            shape.clone(),
            DataType::Float32,
            ChunkGrid::new(RegularChunkGrid::new(chunk_shape.clone().try_into().unwrap())),
            FillValue::from(0.0f32),
        )
            .build(store.clone(), "/test")
            .unwrap();

        let mut chunk_data = vec![0.0f32; 25];
        for i in 0..25 { chunk_data[i] = i as f32; }

        array_write.store_metadata().unwrap();
        array_write.store_chunk_elements(&[0, 0], &chunk_data).unwrap();

        let ro_store: Arc<dyn ReadableStorageTraits> = store;
        let array = Array::open(ro_store, "/test").unwrap();

        let reader = ChunkReader::new(Arc::new(array), true, shape, chunk_shape);

        let (elements, info) = reader.read_chunk_subset::<f32>(
            &[0, 0],
            &[1, 1],
            &[3, 3]
        ).unwrap();

        assert_eq!(info.shape, vec![3, 3]);
        assert_eq!(elements, vec![6.0, 7.0, 8.0, 11.0, 12.0, 13.0, 16.0, 17.0, 18.0]);
    }
}

